import { Component, HostListener, Inject, OnDestroy, OnInit, effect } from '@angular/core';
import { CommonModule, DOCUMENT } from '@angular/common';
import { FormsModule } from '@angular/forms';
import { Router } from '@angular/router';
import { InputTextModule } from 'primeng/inputtext';
import { Table, TableModule } from 'primeng/table';
import { ButtonModule } from 'primeng/button';
import { RippleModule } from 'primeng/ripple';
import { IconField } from 'primeng/iconfield';
import { InputIcon } from 'primeng/inputicon';
import { TagModule } from 'primeng/tag';
import { TooltipModule } from 'primeng/tooltip';
import { SelectModule } from 'primeng/select';
import { MenuItem, MessageService, ConfirmationService } from 'primeng/api';
import { ConfirmDialogModule } from 'primeng/confirmdialog';
import { MenuModule } from 'primeng/menu';

import { User } from '@/models/user.model';
import { UserService } from '@/services/users/users.service';
import { AuthService } from '@/services/auth/auth.service';
import { UsineContextService } from '@/services/usine/usine-context.service';
import { PhoneFormatPipe } from '@/pipes/phone-format.pipe';
import { UtilisateursViewDialog } from '../utilisateurs-view-dialog/utilisateurs-view-dialog';

@Component({
  selector: 'app-utilisateurs-liste',
  standalone: true,
  templateUrl: './utilisateurs-liste.html',
  styleUrl: './utilisateurs-liste.scss',
  imports: [
    CommonModule,
    FormsModule,
    TableModule,
    InputTextModule,
    ButtonModule,
    RippleModule,
    IconField,
    InputIcon,
    TagModule,
    TooltipModule,
    SelectModule,
    ConfirmDialogModule,
    MenuModule,
    PhoneFormatPipe,
    UtilisateursViewDialog,
  ],
  providers: [ConfirmationService],
})
export class UtilisateursListe implements OnInit, OnDestroy {
  users: User[] = [];
  selectedUser: User | null = null;
  loading = false;
  selectedStatus: boolean | null = null;

  viewDialogVisible = false;
  viewUserId: number | null = null;
  viewDialogMode: 'create' | 'edit' = 'edit';

  mobileSearchTerm = '';
  readonly mobilePageSize = 10;
  mobileVisibleCount = this.mobilePageSize;
  private readonly mobileBreakpoint = 768;
  private readonly mobilePwaClass = 'utilisateurs-mobile-pwa';
  private readyForUsineReload = false;

  statusOptions = [
    { label: 'Actif', value: true },
    { label: 'Inactif', value: false }
  ];

  mobileStatusMenuItems: MenuItem[] = [
    { label: 'Tous les statuts', command: () => this.applyMobileStatusFilter(null) },
    { label: 'Actif', command: () => this.applyMobileStatusFilter(true) },
    { label: 'Inactif', command: () => this.applyMobileStatusFilter(false) },
  ];

  get canCreate(): boolean { return this.authService.hasPermission('users.create'); }
  get canUpdate(): boolean { return this.authService.hasPermission('users.update'); }
  get canDelete(): boolean { return this.authService.hasPermission('users.delete'); }

  constructor(
    private userService: UserService,
    private router: Router,
    private messageService: MessageService,
    private confirmationService: ConfirmationService,
    private authService: AuthService,
    private usineContext: UsineContextService,
    @Inject(DOCUMENT) private document: Document
  ) {
    effect(() => {
      this.usineContext.currentUsineId();
      if (!this.readyForUsineReload) return;
      this.loadUsers();
    });
  }

  ngOnInit() {
    this.readyForUsineReload = true;
    this.loadUsers();
    this.syncMobilePwaMode();
  }

  ngOnDestroy() {
    this.document.body.classList.remove(this.mobilePwaClass);
  }

  @HostListener('window:resize')
  onWindowResize() {
    this.syncMobilePwaMode();
  }

  goHome() {
    this.router.navigate(['/']);
  }

  onMobileSearchChange() {
    this.mobileVisibleCount = this.mobilePageSize;
  }

  get mobileFilteredUsers(): User[] {
    const term = this.mobileSearchTerm.trim().toLowerCase();
    if (!term) return this.users;
    return this.users.filter(
      (u) =>
        (u.nom_complet && u.nom_complet.toLowerCase().includes(term)) ||
        (u.email && u.email.toLowerCase().includes(term)) ||
        (u.phone && u.phone.replace(/\s/g, '').includes(term)) ||
        (u.reference && u.reference.toLowerCase().includes(term))
    );
  }

  get mobileVisibleUsers(): User[] {
    return this.mobileFilteredUsers.slice(0, this.mobileVisibleCount);
  }

  get canLoadMoreMobile(): boolean {
    return this.mobileVisibleCount < this.mobileFilteredUsers.length;
  }

  loadMoreMobile() {
    this.mobileVisibleCount += this.mobilePageSize;
  }

  trackByUserId(_index: number, user: User): number {
    return user.id;
  }

  private syncMobilePwaMode() {
    if (typeof window === 'undefined') return;
    if (window.innerWidth <= this.mobileBreakpoint) {
      this.document.body.classList.add(this.mobilePwaClass);
    } else {
      this.document.body.classList.remove(this.mobilePwaClass);
    }
  }

  loadUsers() {
    this.loading = true;

    const filters = this.selectedStatus !== null
      ? { is_active: this.selectedStatus }
      : undefined;

    this.userService.getUsers(filters).subscribe({
      next: (response) => {
        if (response.success) {
          this.users = Array.isArray(response.data)
            ? response.data
            : response.data.data;
          this.mobileVisibleCount = this.mobilePageSize;
        }
        this.loading = false;
      },
      error: (error) => {
        console.error('Erreur lors du chargement des utilisateurs:', error);
        this.messageService.add({
          severity: 'error',
          summary: 'Erreur',
          detail: this.getApiErrorDetail(error, 'Impossible de charger les utilisateurs')
        });
        this.loading = false;
      }
    });
  }

  onGlobalFilter(table: Table, event: Event) {
    table.filterGlobal((event.target as HTMLInputElement).value, 'contains');
  }

  filterByStatus() {
    this.loadUsers();
  }

  applyMobileStatusFilter(status: boolean | null) {
    this.selectedStatus = status;
    this.loadUsers();
  }

  onRowSelect(event: any) {
    if (!this.canUpdate) return;
    this.openEditDialog(event.data.id);
  }

  openViewDialog(event: Event, userId: number) {
    event.stopPropagation();
    this.openEditDialog(userId);
  }

  openCreateDialog() {
    if (!this.canCreate) return;
    this.viewDialogMode = 'create';
    this.viewUserId = null;
    this.viewDialogVisible = true;
  }

  openEditDialog(userId: number) {
    if (!this.canUpdate) return;
    this.viewDialogMode = 'edit';
    this.viewUserId = userId;
    this.viewDialogVisible = true;
  }

  onDialogUserSaved(event: { user: User; mode: 'create' | 'edit' }) {
    this.loadUsers();

    this.messageService.add({
      severity: 'success',
      summary: 'Succes',
      detail: event.mode === 'create' ? 'Utilisateur cree avec succes' : 'Utilisateur modifie avec succes',
    });
  }

  goToEdit(event: Event, userId: number) {
    event.stopPropagation();
    this.openEditDialog(userId);
  }

  toggleStatus(event: Event, userId: number) {
    event.stopPropagation();

    const user = this.users.find(u => u.id === userId);
    const action = user?.is_active ? 'désactiver' : 'activer';

    this.confirmationService.confirm({
      message: `Voulez-vous vraiment ${action} cet utilisateur ?`,
      header: 'Confirmation',
      icon: 'pi pi-exclamation-triangle',
      acceptLabel: 'Oui',
      rejectLabel: 'Non',
      accept: () => {
        this.userService.toggleUserStatus(userId).subscribe({
          next: (response) => {
            if (response.success) {
              this.messageService.add({
                severity: 'success',
                summary: 'Succès',
                detail: response.message
              });
              this.loadUsers();
            }
          },
          error: (error) => {
            console.error('Erreur:', error);
            this.messageService.add({
              severity: 'error',
              summary: 'Erreur',
              detail: this.getApiErrorDetail(error, 'Impossible de changer le statut de l\'utilisateur')
            });
          }
        });
      }
    });
  }

  deleteUser(event: Event, userId: number) {
    event.stopPropagation();

    this.confirmationService.confirm({
      message: 'Êtes-vous sûr de vouloir supprimer cet utilisateur ? Cette action est irréversible.',
      header: 'Confirmation de suppression',
      icon: 'pi pi-exclamation-triangle',
      acceptLabel: 'Oui, supprimer',
      rejectLabel: 'Annuler',
      acceptButtonStyleClass: 'p-button-danger',
      accept: () => {
        this.userService.deleteUser(userId).subscribe({
          next: (response) => {
            if (response.success) {
              this.messageService.add({
                severity: 'success',
                summary: 'Succès',
                detail: 'Utilisateur supprimé avec succès'
              });
              this.loadUsers();
            }
          },
          error: (error) => {
            console.error('Erreur:', error);
            const apiMessage = this.getApiErrorDetail(error, 'Impossible de supprimer l\'utilisateur');
            this.messageService.add({ severity: 'error', summary: 'Erreur', detail: apiMessage });
            if (error?.error?.errors?.action === 'archive') {
              this.proposeArchiveUser(userId);
            }
          }
        });
      }
    });
  }

  archiveUserAction(event: Event, userId: number): void {
    event.stopPropagation();

    this.confirmationService.confirm({
      message: 'Voulez-vous archiver cet utilisateur ? Il sera désactivé et ne pourra plus se connecter.',
      header: 'Archiver l\'utilisateur',
      icon: 'pi pi-inbox',
      acceptLabel: 'Oui, archiver',
      rejectLabel: 'Annuler',
      accept: () => {
        this.userService.archiveUser(userId).subscribe({
          next: (response) => {
            if (response.success) {
              this.messageService.add({ severity: 'success', summary: 'Succès', detail: 'Utilisateur archivé avec succès' });
              this.loadUsers();
            }
          },
          error: (error) => {
            const apiMessage = this.getApiErrorDetail(error, 'Impossible d\'archiver l\'utilisateur');
            this.messageService.add({ severity: 'error', summary: 'Erreur', detail: apiMessage });
          }
        });
      }
    });
  }

  private proposeArchiveUser(userId: number): void {
    const user = this.users.find(u => u.id === userId);
    if (user?.is_archived) return;

    this.confirmationService.confirm({
      message: 'Cet utilisateur a des données liées. Voulez-vous l\'archiver à la place ?',
      header: 'Archiver l\'utilisateur',
      icon: 'pi pi-info-circle',
      acceptLabel: 'Oui, archiver',
      rejectLabel: 'Non',
      accept: () => {
        this.userService.archiveUser(userId).subscribe({
          next: (response) => {
            if (response.success) {
              this.messageService.add({ severity: 'success', summary: 'Succès', detail: 'Utilisateur archivé avec succès' });
              this.loadUsers();
            }
          },
          error: (error) => {
            this.messageService.add({
              severity: 'error',
              summary: 'Erreur',
              detail: this.getApiErrorDetail(error, 'Impossible d\'archiver l\'utilisateur'),
            });
          }
        });
      }
    });
  }

  private getApiErrorDetail(error: unknown, fallback: string): string {
    const validationMessages = this.extractValidationMessages(error);
    if (validationMessages.length > 0) {
      return validationMessages.join('; ');
    }

    const apiMessage = this.extractApiMessage(error);
    if (apiMessage) {
      return apiMessage;
    }

    return fallback;
  }

  private extractApiMessage(error: unknown): string | null {
    const message = (error as { error?: { message?: unknown } })?.error?.message;
    if (typeof message !== 'string') {
      return null;
    }

    const trimmedMessage = message.trim();
    return trimmedMessage.length > 0 ? trimmedMessage : null;
  }

  private extractValidationMessages(error: unknown): string[] {
    const validationErrors = (error as { error?: { errors?: unknown } })?.error?.errors;
    if (!validationErrors || typeof validationErrors !== 'object') {
      return [];
    }

    return Object.values(validationErrors as Record<string, unknown>)
      .flatMap((value) => (Array.isArray(value) ? value : [value]))
      .map((message) => String(message).trim())
      .filter((message) => message.length > 0);
  }

  getInitials(nomComplet: string): string {
    if (!nomComplet) return '??';

    const parts = nomComplet.trim().split(' ');
    if (parts.length >= 2) {
      return (parts[0][0] + parts[parts.length - 1][0]).toUpperCase();
    }
    return nomComplet.substring(0, 2).toUpperCase();
  }

}

